async function fetchMaterialContent(material_id, user_id) {
  const { data, error } = await supabase
    .from('materials')
    .select('title, description, file_url, file_type')
    .eq('id', material_id)
    .eq('is_deleted', false)
    .single();

  if (error || !data) return null;
  // Return a text representation — the ai-proxy Edge Function handles file fetching if needed
  return JSON.stringify(data);
}

async function fetchNoteContent(note_id, user_id) {
  const { data, error } = await supabase
    .from('notes')
    .select('title, body')
    .eq('id', note_id)
    .eq('user_id', user_id)
    .eq('is_deleted', false)
    .single();

  if (error || !data) return null;
  return `${data.title}\n\n${data.body}`;
}

import supabase from '../utils/supabaseClient.js';

const MAX_FILE_SIZE = 50 * 1024 * 1024; // 50MB
const ALLOWED_TYPES = ['application/pdf', 'image/jpeg', 'image/png', 'image/webp'];

// ── GET /materials ─────────────────────────────────────────────────────────────
// Paginated list filtered by course or class
export async function getMaterials(req, res) {
  const { course_id, class_id, page = 1, limit = 20, type } = req.query;

  if (!course_id) {
    return res.status(400).json({ error: 'course_id is required' });
  }

  const pageNum = Math.max(1, parseInt(page));
  const limitNum = Math.min(50, Math.max(1, parseInt(limit)));
  const from = (pageNum - 1) * limitNum;

  try {
    let query = supabase
      .from('materials')
      .select(`
        id, title, description, file_url, file_type, file_size,
        course_id, class_id, uploaded_by,
        created_at,
        profiles:uploaded_by ( id, full_name, avatar_url )
      `, { count: 'exact' })
      .eq('course_id', course_id)
      .eq('is_deleted', false)
      .order('created_at', { ascending: false })
      .range(from, from + limitNum - 1);

    if (class_id) query = query.eq('class_id', class_id);
    if (type) query = query.eq('file_type', type);

    const { data, error, count } = await query;

    if (error) {
      console.error('[getMaterials] DB error:', error);
      return res.status(500).json({ error: 'Failed to fetch materials' });
    }

    return res.json({
      data,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total: count,
        totalPages: Math.ceil(count / limitNum),
      },
    });
  } catch (err) {
    console.error('[getMaterials] Unexpected error:', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
}

