// ── POST /materials ────────────────────────────────────────────────────────────
// Metadata only — client uploads file directly to Supabase Storage,
// then calls this endpoint with the resulting file_url
export async function createMaterial(req, res) {
  const { title, description, file_url, file_type, file_size, course_id, class_id } = req.body;

  // Validate required fields
  if (!title?.trim()) return res.status(400).json({ error: 'title is required' });
  if (!file_url?.trim()) return res.status(400).json({ error: 'file_url is required' });
  if (!file_type?.trim()) return res.status(400).json({ error: 'file_type is required' });
  if (!course_id) return res.status(400).json({ error: 'course_id is required' });

  if (title.trim().length > 200) return res.status(400).json({ error: 'title too long (max 200)' });
  if (description && description.length > 1000) return res.status(400).json({ error: 'description too long (max 1000)' });
  if (file_size && file_size > MAX_FILE_SIZE) return res.status(400).json({ error: 'File exceeds 50MB limit' });
  if (!ALLOWED_TYPES.includes(file_type)) return res.status(400).json({ error: `File type not allowed. Allowed: ${ALLOWED_TYPES.join(', ')}` });

  try {
    const { data, error } = await supabase
      .from('materials')
      .insert({
        title: title.trim(),
        description: description?.trim() ?? null,
        file_url,
        file_type,
        file_size: file_size ?? null,
        course_id,
        class_id: class_id ?? null,
        uploaded_by: req.user.id,
        is_deleted: false,
      })
      .select()
      .single();

    if (error) {
      console.error('[createMaterial] DB insert error:', error);
      return res.status(500).json({ error: 'Failed to save material' });
    }

    // Fire push notification async — don't block the response
    triggerMaterialPush({
      material_id: data.id,
      title: data.title,
      course_id: data.course_id,
      class_id: data.class_id,
      uploaded_by: req.user.id,
    }).catch(err => console.error('[createMaterial] Push notification failed:', err));

    return res.status(201).json(data);
  } catch (err) {
    console.error('[createMaterial] Unexpected error:', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
}

// ── DELETE /materials/:id ──────────────────────────────────────────────────────
// Soft delete — only the uploader can delete their own material
export async function deleteMaterial(req, res) {
  const { id } = req.params;

  try {
    // Verify ownership first
    const { data: existing, error: fetchError } = await supabase
      .from('materials')
      .select('id, uploaded_by')
      .eq('id', id)
      .eq('is_deleted', false)
      .single();

    if (fetchError || !existing) {
      return res.status(404).json({ error: 'Material not found' });
    }

    if (existing.uploaded_by !== req.user.id) {
      return res.status(403).json({ error: 'Not authorized to delete this material' });
    }

    const { error } = await supabase
      .from('materials')
      .update({ is_deleted: true })
      .eq('id', id);

    if (error) {
      console.error('[deleteMaterial] DB error:', error);
      return res.status(500).json({ error: 'Failed to delete material' });
    }

    return res.json({ success: true });
  } catch (err) {
    console.error('[deleteMaterial] Unexpected error:', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
}

// ── Helper: fire push notification via Supabase Edge Function ─────────────────
async function triggerMaterialPush({ material_id, title, course_id, class_id, uploaded_by }) {
  const supabaseUrl = process.env.SUPABASE_URL;
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

  const res = await fetch(`${supabaseUrl}/functions/v1/send-material-push`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${serviceKey}`,
    },
    body: JSON.stringify({ material_id, title, course_id, class_id, uploaded_by }),
  });

  if (!res.ok) {
    throw new Error(`Push function returned ${res.status}: ${await res.text()}`);
  }
}

/**
 * contexts/PremiumContext.tsx
 *
 * SINGLE SOURCE OF TRUTH for premium status across the entire app.
 *
 * HOW IT WORKS:
 *  1. On mount, reads AsyncStorage cache for instant cold-start value
 *  2. Queries Supabase (subscriptions + profiles.is_premium + role)
 *  3. Subscribes to Realtime on both `subscriptions` and `profiles` tables
 *  4. Re-checks whenever the app comes back to foreground (AppState)
 *  5. Exposes refresh() so payment-pending.tsx can force an immediate re-check
 *
 * PREMIUM LOGIC (mirrors every existing screen):
 *   isPremium = subscriptions row with status='active'
 *            OR profiles.is_premium === true
 *            OR profiles.role === 'admin'
 *
 * USAGE — any screen or component, one line:
 *   const { isPremium, isLoading } = usePremium()
 *
 * ADDING A NEW PREMIUM FEATURE:
 *   Just call usePremium() in the new screen. Nothing else needed.
 *   When the user upgrades, every mounted component updates automatically.
 */

import AsyncStorage from '@react-native-async-storage/async-storage'
import { createContext, useContext, useEffect, useRef, useState, useCallback } from 'react'
import { AppState, AppStateStatus } from 'react-native'
import { supabase } from '@/core/api/supabase'

// ─── Cache key ────────────────────────────────────────────────────────────────
const PREMIUM_CACHE_KEY = 'studentshare_is_premium_v1'

// ─── Context shape ────────────────────────────────────────────────────────────
type PremiumContextValue = {
  /** Whether the current user has an active premium subscription */
  isPremium: boolean
  /** True only during the very first cold-start check (cache not yet read) */
  isLoading: boolean
  /** Call this to force an immediate re-check (e.g. after payment confirmed) */
  refresh: () => Promise<void>
}

const PremiumContext = createContext<PremiumContextValue>({
  isPremium: false,
  isLoading: true,
  refresh: async () => {},
})

// ─── Core check ───────────────────────────────────────────────────────────────
async function checkPremium(userId: string): Promise<boolean> {
  const [subRes, profileRes] = await Promise.all([
    supabase
      .from('subscriptions')
      .select('id')
      .eq('user_id', userId)
      .eq('status', 'active')
      .limit(1)
      .maybeSingle(),
    supabase
      .from('profiles')
      .select('is_premium, role')
      .eq('id', userId)
      .single(),
  ])

  return (
    subRes.data != null ||
    profileRes.data?.is_premium === true ||
    profileRes.data?.role === 'admin'
  )
}

// ─── Provider ────────────────────────────────────────────────────────────────
export function PremiumProvider({ children }: { children: React.ReactNode }) {
  const [isPremium, setIsPremium] = useState(false)
  const [isLoading, setIsLoading] = useState(true)
  const userIdRef  = useRef<string | null>(null)
  const mountedRef = useRef(true)

  // ── Hydrate from cache immediately, then verify with Supabase ────────────
  useEffect(() => {
    mountedRef.current = true

    const init = async () => {
      // 1. Read cache for instant render
      try {
        const cached = await AsyncStorage.getItem(PREMIUM_CACHE_KEY)
        if (cached !== null && mountedRef.current) {
          setIsPremium(cached === 'true')
          setIsLoading(false)
        }
      } catch {}

      // 2. Get current user
      try {
        const { data: { session } } = await supabase.auth.getSession()
        if (!session?.user) {
          if (mountedRef.current) { setIsPremium(false); setIsLoading(false) }
          await AsyncStorage.setItem(PREMIUM_CACHE_KEY, 'false').catch(() => {})
          return
        }

        userIdRef.current = session.user.id

        // 3. Live check
        const result = await checkPremium(session.user.id)
        if (mountedRef.current) { setIsPremium(result); setIsLoading(false) }
        await AsyncStorage.setItem(PREMIUM_CACHE_KEY, String(result)).catch(() => {})
      } catch {
        if (mountedRef.current) setIsLoading(false)
      }
    }

    void init()

    // ── Auth state changes (sign-in / sign-out) ──────────────────────────
    const { data: { subscription: authSub } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (event === 'SIGNED_OUT' || !session?.user) {
        userIdRef.current = null
        if (mountedRef.current) { setIsPremium(false); setIsLoading(false) }
        await AsyncStorage.setItem(PREMIUM_CACHE_KEY, 'false').catch(() => {})
        return
      }
      if (event === 'SIGNED_IN' && session.user.id !== userIdRef.current) {
        userIdRef.current = session.user.id
        try {
          const result = await checkPremium(session.user.id)
          if (mountedRef.current) { setIsPremium(result); setIsLoading(false) }
          await AsyncStorage.setItem(PREMIUM_CACHE_KEY, String(result)).catch(() => {})
        } catch {}
      }
    })

    return () => {
      mountedRef.current = false
      authSub.unsubscribe()
    }
  }, [])

  // ── Realtime: subscriptions table ────────────────────────────────────────
  useEffect(() => {
    if (!userIdRef.current) return

    const userId = userIdRef.current

    const channel = supabase
      .channel(`premium-watch-${userId}`)
      .on(
        'postgres_changes',
        {
          event:  '*',
          schema: 'public',
          table:  'subscriptions',
          filter: `user_id=eq.${userId}`,
        },
        async () => {
          if (!mountedRef.current) return
          try {
            const result = await checkPremium(userId)
            if (mountedRef.current) setIsPremium(result)
            await AsyncStorage.setItem(PREMIUM_CACHE_KEY, String(result)).catch(() => {})
          } catch {}
        },
      )
      .on(
        'postgres_changes',
        {
          event:  '*',
          schema: 'public',
          table:  'profiles',
          filter: `id=eq.${userId}`,
        },
        async () => {
          if (!mountedRef.current) return
          try {
            const result = await checkPremium(userId)
            if (mountedRef.current) setIsPremium(result)
            await AsyncStorage.setItem(PREMIUM_CACHE_KEY, String(result)).catch(() => {})
          } catch {}
        },
      )
      .subscribe()

    return () => { supabase.removeChannel(channel) }
  }, [userIdRef.current]) // re-subscribe if userId changes

  // ── AppState: re-check when app comes back to foreground ─────────────────
  useEffect(() => {
    const handler = async (state: AppStateStatus) => {
      if (state !== 'active' || !userIdRef.current || !mountedRef.current) return
      try {
        const result = await checkPremium(userIdRef.current)
        if (mountedRef.current) setIsPremium(result)
        await AsyncStorage.setItem(PREMIUM_CACHE_KEY, String(result)).catch(() => {})
      } catch {}
    }

    const sub = AppState.addEventListener('change', handler)
    return () => sub.remove()
  }, [])

  // ── Manual refresh (called by payment-pending after upgrade confirmed) ───
  const refresh = useCallback(async () => {
    if (!userIdRef.current) return
    try {
      const result = await checkPremium(userIdRef.current)
      if (mountedRef.current) setIsPremium(result)
      await AsyncStorage.setItem(PREMIUM_CACHE_KEY, String(result)).catch(() => {})
    } catch {}
  }, [])

  return (
    <PremiumContext.Provider value={{ isPremium, isLoading, refresh }}>
      {children}
    </PremiumContext.Provider>
  )
}

// ─── Hook ────────────────────────────────────────────────────────────────────
export function usePremium(): PremiumContextValue {
  return useContext(PremiumContext)
}

/**
 * app/(tabs)/_layout.tsx
 *
 * Tab bar: Home · Search · Forum FAB · Library · Profile
 *
 * Forum FAB (centre):
