import { supabase } from '@/core/api/supabase'
import { Q } from '@nozbe/watermelondb'
import database from '@/database'
import NetInfo from '@react-native-community/netinfo'
import { mapRemoteToLocal, mapLocalToRemote } from './mapping'

// ─── Per-table sync config ───────────────────────────────────────────────────

type CursorType = 'bigint' | 'iso'
interface TableConfig {
  cursorCol:  string
  cursorType: CursorType
  localName:  string
}

const TABLE_CONFIG: Record<string, TableConfig> = {
  users:                 { cursorCol: 'updated_at', cursorType: 'iso',    localName: 'users'             },
  courses:               { cursorCol: 'updated_at', cursorType: 'iso',    localName: 'courses'           },
  lecturers:             { cursorCol: 'updated_at', cursorType: 'iso',    localName: 'lecturers'         },
  sq_posts:              { cursorCol: 'updated_at', cursorType: 'iso',    localName: 'posts'             },
  sq_comments:           { cursorCol: 'updated_at', cursorType: 'iso',    localName: 'comments'          },
  materials:             { cursorCol: 'updated_at', cursorType: 'iso',    localName: 'materials'         },
  notes:                 { cursorCol: 'updated_at', cursorType: 'iso',    localName: 'notes'             },
  conversations:         { cursorCol: 'updated_at', cursorType: 'iso',    localName: 'conversations'     },
  sq_messages:           { cursorCol: 'created_at', cursorType: 'iso',    localName: 'messages'          },
  sq_post_interactions:  { cursorCol: 'created_at', cursorType: 'iso',    localName: 'post_interactions' },
  bookmarks:             { cursorCol: 'created_at', cursorType: 'iso',    localName: 'bookmarks'         },
}


// ─── Sync Interface (Aliases for external use) ───────────────────────────────

/** Performs a full push and pull sync. Returns Promise<void>. */
export async function triggerSync(userId?: string): Promise<void> {
  try {
    // 1. Get the last sync timestamp
    const lastSyncedAt = Number(await database.adapter.getLocal('last_synced_at')) || 0
    
    // 2. Run the sync cycle
    await runSync(lastSyncedAt)

    // 3. Update the last sync timestamp
    await database.adapter.setLocal('last_synced_at', Date.now().toString())
  } catch (err) {
    console.warn('[Sync] triggerSync failed:', err)
  }
}

/** Processes only the outgoing sync queue. Returns Promise<void>. */
export async function processOutgoingQueue(): Promise<void> {
  await pushOutbox()
}

// ─── Queue a mutation for later sync ─────────────────────────────────────────

export async function queueMutation(
  userId: string,
  entity: string,
  operation: string,
  payload: object
): Promise<void> {
  await database.write(async () => {
    await database.collections.get('sync_queue').create((r: any) => {
      r.userId     = userId
      r.entity     = entity
      r.operation  = operation
      r.payload    = JSON.stringify(payload)
      r.status     = 'pending'
      r.retryCount = 0
      r.createdAt  = Date.now()
    })
  })
}

// ─── Push pending outbox items to Supabase ───────────────────────────────────

export async function pushOutbox(): Promise<void> {
  const isOnline = await NetInfo.fetch().then(s => s.isConnected)
  if (!isOnline) return

  try {
    const pending = await database.collections
      .get('sync_queue')
      .query(Q.where('status', 'pending'))
      .fetch() as any[]

    if (pending.length === 0) return;

    for (const item of pending) {
      try {
        const payload = JSON.parse(item.payload)
        
        // Map local entity name to remote Supabase table name
        const tableMap: Record<string, string> = {
          posts:             'sq_posts',
          comments:          'sq_comments',
          messages:          'sq_messages',
          post_interactions: 'sq_post_interactions',
          bookmarks:         'bookmarks', // or 'sq_bookmarks' if prefix is used
          notes:             'notes',
          materials:         'materials',
        }
        const table = tableMap[item.entity] || item.entity

        if (item.operation === 'create_dm') {
          // Special case for DMs: call RPC to get or create on server
          const { data, error } = await supabase.rpc('get_or_create_dm', {
            target_user_id: payload.target_user_id,
          })
          if (error) throw error
          if (data?.id) {
            // Update local record with the remote ID
            await database.write(async () => {
              const convo = await database.collections.get('conversations').find(item.payload.local_id)
              await convo.update((c: any) => { c.remoteId = data.id; c.synced = true })
            })
          }
        } else if (item.operation === 'create' || item.operation === 'update') {
          const { error } = await supabase.from(table).upsert(payload)
          if (error) throw error
        } else if (item.operation === 'delete') {
          const { error } = await supabase
            .from(table)
            .delete()
            .eq('id', payload.id)
          if (error) throw error
        }

        await database.write(async () => {
          await item.update((r: any) => {
            r.status     = 'done'
            r.resolvedAt = Date.now()
          })
        })
      } catch (err) {
        console.warn(`[Sync] Failed to push ${item.entity}/${item.operation}:`, err)
        await database.write(async () => {
          await item.update((r: any) => {
            r.retryCount = (r.retryCount || 0) + 1
            r.lastError  = String(err)
            if (r.retryCount >= 5) r.status = 'failed'
          })
        })
      }
    }
  } catch (err) {
    console.warn('[Sync] pushOutbox error:', err)
  }
}

// ─── Pull changes from Supabase since last sync ──────────────────────────────

export async function pullIncoming(
  table: string,
  since: number   // always Unix ms — we convert per table config
): Promise<any[]> {
  const isOnline = await NetInfo.fetch().then(s => s.isConnected)
  if (!isOnline) return []

  const cfg = TABLE_CONFIG[table]
  if (!cfg) {
    console.warn(`[Sync] No config for table: ${table}`)
    return []
  }

  // Convert cursor to the format the column expects
  const cursorValue = new Date(since).toISOString()

  try {
    const { data, error } = await supabase
      .from(table)
      .select('*')
      .gt(cfg.cursorCol, cursorValue)
      .order(cfg.cursorCol, { ascending: true })

    if (error) throw error
    return data ?? []
  } catch (err) {
    console.warn(`[Sync] pullIncoming error for ${table}:`, err)
    return []
  }
}

// ─── Full sync cycle ─────────────────────────────────────────────────────────

export async function runSync(lastSyncedAt: number = 0): Promise<void> {
  // Always try to push changes first
  await pushOutbox()

  const tables = Object.keys(TABLE_CONFIG)

  for (const table of tables) {
    const cfg  = TABLE_CONFIG[table]
    const rows = await pullIncoming(table, lastSyncedAt)

    if (rows.length === 0) continue

    for (const record of rows) {
      try {
        const collection = database.collections.get(cfg.localName)

        await database.write(async () => {
          const existing = await collection
            .query(Q.where('remote_id', record.id))
            .fetch() as any[]

          const local = (existing[0] || null) as any

          // Handle Soft Deletes from Supabase
          if (record.deleted) {
            if (local) await local.update((r: any) => { r.deleted = true })
            return
          }

          if (!local) {
            // CREATE
            await collection.create((r: any) => {
              mapRemoteToLocal(cfg.localName as any, record, r)
            })
          } else {
            // UPDATE — last-write-wins based on version or updated_at
            const serverTs = record.updated_at ? new Date(record.updated_at).getTime() : 0
            const localTs  = local.serverUpdatedAt || 0

            if (serverTs <= localTs) return

            await local.update((r: any) => {
              mapRemoteToLocal(cfg.localName as any, record, r)
            })
          }
        })
      } catch (err) {
        console.warn(`[Sync] Failed to apply record from ${table}:`, err)
      }
    }
  }
}

import { Q } from '@nozbe/watermelondb';
import database from '../database';

// ─── Helper ──────────────────────────────────────────────────────────────────

const col = (name) => database.collections.get(name);

// Adds an item to the sync_queue outbox for later server sync
async function enqueue(userId, entity, operation, payload) {
  await database.write(async () => {
    await col('sync_queue').create((item) => {
      item.userId     = userId;
      item.entity     = entity;
      item.operation  = operation;
      item.payload    = JSON.stringify(payload);
      item.status     = 'pending';
      item.retryCount = 0;
      item.createdAt  = Date.now();
    });
  });
}

// ─── Posts ───────────────────────────────────────────────────────────────────

export async function createPost(userId, { 
  title, content, imageUrl, pollOptions, replyToId, isAnonymous, 
  author_name, author_handle, author_initials, author_grad, author_avatar_url, author_verified 
}) {
  let newPost;
  await database.write(async () => {
    newPost = await col('posts').create((post) => {
      post.title           = title;
      post.content         = content; // Supabase 'body'
      post.authorId        = userId;
      post.imageUrl        = imageUrl;
      post.pollOptions     = pollOptions ? JSON.stringify(pollOptions) : null;
      post.replyToId       = replyToId;
      post.isAnonymous     = isAnonymous;
      post.authorName      = author_name;
      post.authorHandle    = author_handle;
      post.authorInitials  = author_initials;
      post.authorGrad      = author_grad ? JSON.stringify(author_grad) : null;
      post.authorAvatarUrl = author_avatar_url;
      post.authorVerified  = author_verified;
      post.synced          = false;
      post.deleted         = false;
      post.version         = 1;
      post.createdAt       = Date.now();
      post.updatedAt       = Date.now();
    });
  });

  // Add to outbox — will sync when online
  await enqueue(userId, 'posts', 'create', {
    local_id:          newPost.id,
    title,
    body:              content,
    author_id:         userId,
    image_url:         imageUrl,
    poll_options:      pollOptions,
    reply_to_id:       replyToId,
    is_anonymous:      isAnonymous,
    author_name,
    author_handle,
    author_initials,
    author_grad,
    author_avatar_url,
    author_verified,
  });

  return newPost;
}

export async function updatePost(post, userId, changes) {
  await database.write(async () => {
    await post.update((p) => {
      if (changes.title   !== undefined) p.title   = changes.title;
      if (changes.content !== undefined) p.content = changes.content;
      p.synced    = false;
      p.updatedAt = Date.now();
      p.version   = (p.version || 1) + 1;
    });
  });

  await enqueue(userId, 'posts', 'update', {
    local_id:  post.id,
    remote_id: post.remoteId,
    ...changes,
  });
}

export async function deletePost(post, userId) {
  await database.write(async () => {
    await post.update((p) => {
      p.deleted   = true;
      p.updatedAt = Date.now();
    });
  });

  await enqueue(userId, 'posts', 'delete', {
    id: post.remoteId || post.id,
  });
}

// ─── Post Interactions ───────────────────────────────────────────────────────

export async function togglePostInteraction(userId, postId, type) {
  const collection = col('post_interactions');

  // Try to find an existing interaction of this type for this post
  const existing = await collection
    .query(Q.where('post_id', postId), Q.where('user_id', userId), Q.where('type', type), Q.where('deleted', false))
    .fetch();

  if (existing.length > 0) {
    // UNINTERACT (Soft delete)
    const interaction = existing[0];
    await database.write(async () => {
      await interaction.update((i) => {
        i.deleted = true;
      });
    });

    await enqueue(userId, 'post_interactions', 'delete', {
      id: interaction.remoteId || interaction.id,
      post_id: postId,
      user_id: userId,
      type: type,
    });

    return false; // Resulting state is negative
  } else {
    // INTERACT (Create)
    let newInteraction;
    await database.write(async () => {
      newInteraction = await collection.create((i) => {
        i.userId    = userId;
        i.postId    = postId;
        i.type      = type;
        i.deleted   = false;
        i.createdAt = Date.now();
      });
    });

    await enqueue(userId, 'post_interactions', 'create', {
      local_id:  newInteraction.id,
      user_id:   userId,
      post_id:   postId,
      type:      type,
    });

    return true; // Resulting state is positive
  }
}

// ─── Comments ────────────────────────────────────────────────────────────────

export async function createComment(userId, postId, content) {
  let newComment;
  await database.write(async () => {
    newComment = await col('comments').create((c) => {
      c.postId      = postId;
      c.authorId    = userId;
      c.content     = content;
      c.synced      = false;
      c.deleted     = false;
      c.createdAt   = Date.now();
      c.updatedAt   = Date.now();
    });
  });

  await enqueue(userId, 'comments', 'create', {
    local_id:  newComment.id,
    post_id:   postId,
    author_id: userId,
    content,
  });

  return newComment;
}

export async function getOrCreateConversation(userId, targetUserId, targetUserInfo = {}) {
  const collection = col('conversations');
  
  // 1. Try to find existing DM locally
  const existing = await collection
    .query(
      Q.where('type', 'dm'),
      Q.where('other_user_id', targetUserId),
      Q.where('deleted', false)
    )
    .fetch();

  if (existing.length > 0) return existing[0];

  // 2. Not found locally? Create a "pending" local record
  let newConvo;
  const now = Date.now();
  await database.write(async () => {
    newConvo = await collection.create((c) => {
      c.type            = 'dm';
      c.otherUserId     = targetUserId;
      c.otherUserName   = targetUserInfo.name || 'Student';
      c.otherUserAvatar = targetUserInfo.avatar_url;
      c.unreadCount     = 0;
      c.synced          = false;
      c.deleted         = false;
      c.createdAt       = now;
      c.updatedAt       = now;
      c.lastMessageAt   = now;
    });
  });

  // 3. Enqueue for server side creation (Supabase RPC get_or_create_dm)
  await enqueue(userId, 'conversations', 'create_dm', {
    local_id:       newConvo.id,
    target_user_id: targetUserId,
  });

  return newConvo;
}

// ─── Messages ────────────────────────────────────────────────────────────────

export async function sendMessage(userId, conversationId, content) {
  let newMessage;
  const now = Date.now();

  await database.write(async () => {
    // Write message immediately — UI shows it right away
    newMessage = await col('messages').create((msg) => {
      msg.conversationId = conversationId;
      msg.senderId       = userId;
      msg.content        = content;
      msg.status         = 'sending'; // optimistic
      msg.synced         = false;
      msg.deleted        = false;
      msg.createdAt      = now;
      msg.updatedAt      = now;
    });

    // Update conversation last message preview
    try {
      const convo = await col('conversations').find(conversationId);
      await convo.update((c) => {
        c.lastMessage   = content;
        c.lastMessageAt = now;
        c.updatedAt     = now;
      });
    } catch (e) {
      // conversation might not exist locally yet — ok
    }
  });

  await enqueue(userId, 'messages', 'create', {
    local_id:        newMessage.id,
    conversation_id: conversationId,
    sender_id:       userId,
    content,
  });

  return newMessage;
}

