export async function toggleBookmark(userId, itemId, itemType) {
  const collection = col('bookmarks');
  
  // Try to find an existing bookmark for this item
  const existing = await collection
    .query(Q.where('item_id', itemId), Q.where('user_id', userId), Q.where('deleted', false))
    .fetch();

  if (existing.length > 0) {
    // UNBOOKMARK (Soft delete)
    const bookmark = existing[0];
    await database.write(async () => {
      await bookmark.update((b) => {
        b.deleted = true;
      });
    });

    await enqueue(userId, 'bookmarks', 'delete', {
      id: bookmark.remoteId || bookmark.id,
      item_id: itemId,
      user_id: userId,
    });

    return false; // Resulting state is unbookmarked
  } else {
    // BOOKMARK (Create)
    let newBookmark;
    await database.write(async () => {
      newBookmark = await collection.create((b) => {
        b.userId    = userId;
        b.itemId    = itemId;
        b.itemType  = itemType;
        b.deleted   = false;
        b.createdAt = Date.now();
      });
    });

    await enqueue(userId, 'bookmarks', 'create', {
      local_id:  newBookmark.id,
      user_id:   userId,
      item_id:   itemId,
      item_type: itemType,
    });

    return true; // Resulting state is bookmarked
  }
}

