export async function toggleBookmark(userId, materialId, noteId) {
  const collection = col('bookmarks');
  const existing = await collection
    .query(
      Q.where('user_id',     userId),
      Q.where('material_id', materialId || null),
      Q.where('note_id',     noteId     || null),
      Q.where('deleted',     false)
    )
    .fetch();

  if (existing.length > 0) {
    const bookmark = existing[0];
    await database.write(async () => {
      await bookmark.update((b) => { b.deleted = true; });
    });
    await enqueue(userId, 'bookmarks', 'delete', { id: bookmark.remoteId || bookmark.id });
    return false;
  } else {
    let newBookmark;
    await database.write(async () => {
      newBookmark = await collection.create((b) => {
        b.userId     = userId;
        b.materialId = materialId || null;
        b.noteId     = noteId     || null;
        b.deleted    = false;
        b.createdAt  = Date.now();
      });
    });
    await enqueue(userId, 'bookmarks', 'create', {
      local_id:    newBookmark.id,
      material_id: materialId,
      note_id:     noteId,
    });
    return true;
  }
}

// ─── Seeding from server data ─────────────────────────────────────────────────
// Called by the sync engine to write server records into local DB

export async function upsertFromServer(tableName, records) {
  if (!records?.length) return;

  await database.write(async () => {
    const collection = col(tableName);

    for (const record of records) {
      // Try to find existing record by remote_id
      const existing = await collection
        .query(Q.where('remote_id', record.id))
        .fetch();

      if (existing.length > 0) {
        // Update existing
        await existing[0].update((local) => {
          Object.keys(record).forEach((key) => {
            if (key === 'id') return; // skip remote id field
            const camel = key.replace(/_([a-z])/g, (_, c) => c.toUpperCase());
            if (camel in local) local[camel] = record[key];
          });
          local.serverUpdatedAt = new Date(record.updated_at).getTime();
          local.synced = true;
        });
      } else {
        // Create new local record from server data
        await collection.create((local) => {
          local.remoteId = record.id;
          Object.keys(record).forEach((key) => {
            if (key === 'id') return;
            const camel = key.replace(/_([a-z])/g, (_, c) => c.toUpperCase());
            if (camel in local) local[camel] = record[key];
          });
          local.serverUpdatedAt = new Date(record.updated_at).getTime();
          local.synced = true;
          local.deleted = false;
          if (!local.createdAt) local.createdAt = Date.now();
          if (!local.updatedAt) local.updatedAt = Date.now();
        });
      }
    }
  });
}

