} from 'react-native'
import { useSafeAreaInsets } from 'react-native-safe-area-context'

import { ROUTES } from '@/core/config/routes'

// ── Storage key ───────────────────────────────────────────────────────────────
export const ONBOARDING_KEY = 'onboarding_complete'

// ── Palette — identical to login.tsx ─────────────────────────────────────────
const P = {
