          ) : (
            <View style={styles.emptyState}>
              <Text style={{ fontSize: 40, marginBottom: 12 }}>🔍</Text>
              <Text style={styles.emptyTitle}>Search StudentSquare</Text>
              <Text style={styles.emptySub}>Results for "{query}"</Text>
