import { useState, useCallback, useEffect } from 'react'
import { Alert } from 'react-native'
import * as FileSystem from 'expo-file-system/legacy'
import { useDownloadRegistry } from '@/lib/useDownloadRegistry'
import { usePremium } from '@/core/entitlements/PremiumProvider'
import {
  addBookmark,
  removeBookmark,
  fetchBookmarkedIds,
  fetchBookmarks,
  addDownload,
  type BookmarkRecord,
} from '@/lib/queries/screens'
import { makeLocalPath, ensureDir } from '@/features/library/utils/downloads'

/**
 * useMaterialsActions — Production-ready hook for bookmarks and downloads.
 * Shared across Study Materials and Library screens to ensure state parity.
 */
export function useMaterialsActions(userId: string | null) {
  const { isPremium } = usePremium()
  const { add: registryAdd, has: registryHas } = useDownloadRegistry()

  const [bookmarkedIds, setBookmarkedIds] = useState<Set<string>>(new Set())
  const [bookmarks, setBookmarks] = useState<BookmarkRecord[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const [isSyncing, setIsSyncing] = useState(false)

  // Hydrate bookmarks on mount or userId change
  const refreshBookmarks = useCallback(async () => {
    if (!userId) {
      setBookmarkedIds(new Set())
      setBookmarks([])
      return
    }
    try {
      // We fetch both the IDs (for fast lookups) and full records (for Library)
      const [ids, records] = await Promise.all([
        fetchBookmarkedIds(userId),
        fetchBookmarks(userId),
      ])
      setBookmarkedIds(ids)
      setBookmarks(records)
    } catch (error) {
      console.warn('[useMaterialsActions] Bookmark refresh failed:', error)
    }
  }, [userId])

  useEffect(() => {
    refreshBookmarks()
  }, [refreshBookmarks])

  const toggleBookmark = useCallback(async (materialId: string) => {
    if (!userId) {
      Alert.alert('Sign In', 'You need to be signed in to save materials.')
      return
    }

    const isBookmarked = bookmarkedIds.has(materialId)

    // Optimistic UI update
    setBookmarkedIds(prev => {
      const next = new Set(prev)
      if (isBookmarked) next.delete(materialId)
      else next.add(materialId)
      return next
    })

    try {
      if (isBookmarked) {
        await removeBookmark(userId, materialId)
        setBookmarks(prev => prev.filter(b => b.material_id !== materialId))
      } else {
        await addBookmark(userId, materialId)
        // Refresh to get the full Material record for the Library
        refreshBookmarks()
      }
    } catch (error) {
      // Rollback
      setBookmarkedIds(prev => {
        const next = new Set(prev)
        if (isBookmarked) next.add(materialId)
        else next.delete(materialId)
        return next
      })
      Alert.alert('Error', 'Failed to update bookmark. Please try again.')
    }
  }, [userId, bookmarkedIds, refreshBookmarks])

  const downloadMaterial = useCallback(async (material: { id: string; file_url: string; title: string; is_premium: boolean }) => {
    if (!userId) {
      Alert.alert('Sign In', 'You need to be signed in to download materials.')
      return
    }

    if (material.is_premium && !isPremium) {
      Alert.alert('Premium Content', 'This material is for Premium members only.')
      return
    }

    if (registryHas(material.id)) {
      Alert.alert('Already Offline', 'This file is already available offline in your Library.')
      return
    }

    setIsSyncing(true)

    try {
      await ensureDir()
      const localPath = makeLocalPath(material.id, material.file_url)

      const result = await FileSystem.downloadAsync(material.file_url, localPath)

      if (result.status !== 200) {
        throw new Error(`Download failed with status ${result.status}`)
      }

      await addDownload(userId, material.id)
      registryAdd(material.id)

      Alert.alert('Saved Offline', 'Material is now available in your Library Downloads.')
    } catch (error: any) {
      console.error('[downloadMaterial] Error:', error)
      Alert.alert('Save Failed', 'Could not save for offline access. Please check your connection.')
    } finally {
      setIsSyncing(false)
    }
  }, [userId, isPremium, registryAdd, registryHas])

  return {
    bookmarks,
    bookmarkedIds,
    toggleBookmark,
    downloadMaterial,
    isSyncing,
    isLoading,
    refreshBookmarks,
  }
}

import { Ionicons } from '@expo/vector-icons'
import AsyncStorage from '@react-native-async-storage/async-storage'
import { useFocusEffect, useRouter } from 'expo-router'
import { useCallback, useState } from 'react'
import {
  ActivityIndicator,
  Alert,
  FlatList,
  StyleSheet,
  Text,
  TouchableOpacity,
  View,
} from 'react-native'
import { supabase } from '@/core/api/supabase'
import { fetchBookmarks, removeBookmark, type BookmarkRecord } from '@/lib/queries/screens'
import { useNetworkStatus } from '@/hooks/useNetworkStatus'

const TYPE_META: Record<string, { label: string; color: string; icon: string }> = {
  past_question: { label: 'Past Question', color: '#3B82F6', icon: 'document-text' },
  slide:         { label: 'Slide',         color: '#8B5CF6', icon: 'easel' },
  book:          { label: 'Book',          color: '#10B981', icon: 'book' },
  tutorial:      { label: 'Tutorial',      color: '#F59E0B', icon: 'play-circle' },
}

const BOOKMARKS_CACHE_KEY = (userId: string) => `bookmarks_cache_${userId}`

export default function BookmarksScreen() {
  const router = useRouter()
  const { isOffline } = useNetworkStatus()

  const [bookmarks,   setBookmarks]   = useState<BookmarkRecord[]>([])
  const [loading,     setLoading]     = useState(true)
  const [userId,      setUserId]      = useState<string | null>(null)
  const [removing,    setRemoving]    = useState<string | null>(null)
  const [isFromCache, setIsFromCache] = useState(false)

  useFocusEffect(
    useCallback(() => {
      supabase.auth.getUser().then(({ data: { user } }) => {
        if (user) { setUserId(user.id); loadBookmarks(user.id) }
      })
    }, [])
  )

  async function loadBookmarks(uid: string) {
    setLoading(true)
    try {
      const raw = await AsyncStorage.getItem(BOOKMARKS_CACHE_KEY(uid))
      if (raw) {
        const cached = JSON.parse(raw) as BookmarkRecord[]
        if (cached.length > 0) { setBookmarks(cached); setIsFromCache(true); setLoading(false) }
      }
    } catch {}

    if (isOffline) { setLoading(false); return }

    try {
      const data = await fetchBookmarks(uid)
      setBookmarks(data)
      setIsFromCache(false)
      await AsyncStorage.setItem(BOOKMARKS_CACHE_KEY(uid), JSON.stringify(data))
    } catch (e) {
      console.error(e)
      if (bookmarks.length === 0) setBookmarks([])
    } finally {
      setLoading(false)
    }
  }

  async function handleRemove(bookmark: BookmarkRecord) {
    if (!userId) return
    if (isOffline) { Alert.alert('You are offline 📡', 'Connect to the internet to remove bookmarks.'); return }
    Alert.alert('Remove Bookmark', `Remove "${bookmark.material.title}" from saved?`, [
      { text: 'Cancel', style: 'cancel' },
      { text: 'Remove', style: 'destructive', onPress: async () => {
        setRemoving(bookmark.id)
        try {
          await removeBookmark(userId, bookmark.material_id)
          const updated = bookmarks.filter(b => b.id !== bookmark.id)
          setBookmarks(updated)
          await AsyncStorage.setItem(BOOKMARKS_CACHE_KEY(userId), JSON.stringify(updated))
        } catch { Alert.alert('Error', 'Could not remove bookmark.') }
        finally { setRemoving(null) }
      }},
    ])
  }

  // ── Quiz navigation ──────────────────────────────────────────────────────
  function openQuiz(bookmark: BookmarkRecord) {
    router.push({
      pathname: '/quiz-flashcards' as any,
      params: {
        material_id:   bookmark.material.id,
        title:         bookmark.material.title,
        file_url:      bookmark.material.file_url,
        type:          bookmark.material.type,
        auto_generate: '1',
      },
    })
  }

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'
    if (days === 1) return 'Yesterday'
    if (days < 7) return `${days} days ago`
    return new Date(dateStr).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' })
  }

  return (
    <View style={styles.container}>

      {/* ── Dark Hero ── */}
      <View style={styles.hero}>
        <View style={styles.circleTopRight} />
        <View style={styles.circleBottomLeft} />

        <TouchableOpacity style={styles.backBtn} onPress={() => router.back()}>
          <Ionicons name="arrow-back" size={20} color="#E2E8F0" />
        </TouchableOpacity>

        <View style={styles.heroIcon}>
          <Ionicons name="bookmark" size={26} color="#F59E0B" />
        </View>
        <Text style={styles.heroTitle}>Saved Materials</Text>
        <Text style={styles.heroSub}>
          {loading && bookmarks.length === 0
            ? 'Loading...'
            : `${bookmarks.length} saved material${bookmarks.length !== 1 ? 's' : ''}`}
        </Text>
      </View>

      {/* ── Offline / cache banner ── */}
      {isOffline && (
        <View style={styles.offlineBanner}>
          <Ionicons name="cloud-offline-outline" size={13} color="#92400E" />
          <Text style={styles.offlineBannerText}>Offline — showing saved bookmarks</Text>
        </View>
      )}
      {!isOffline && isFromCache && !loading && (
        <View style={styles.cacheBanner}>
          <Ionicons name="refresh-outline" size={13} color="#1D4ED8" />
          <Text style={styles.cacheBannerText}>Syncing your bookmarks…</Text>
        </View>
      )}

      {/* ── Content ── */}
      {loading && bookmarks.length === 0 ? (
        <View style={styles.loadingBox}>
          <ActivityIndicator size="large" color="#F59E0B" />
          <Text style={styles.loadingText}>Loading bookmarks...</Text>
        </View>
      ) : (
        <FlatList
          data={bookmarks}
          keyExtractor={item => item.id}
          contentContainerStyle={styles.list}
          ListEmptyComponent={
            <View style={styles.empty}>
              <View style={styles.emptyIconBox}>
                <Ionicons name={isOffline ? 'cloud-offline-outline' : 'bookmark-outline'} size={36} color="#94A3B8" />
              </View>
              <Text style={styles.emptyTitle}>
                {isOffline ? 'No cached bookmarks' : 'No saved materials'}
              </Text>
              <Text style={styles.emptySub}>
                {isOffline
                  ? 'Connect to the internet to load your saved materials.'
                  : 'Tap the bookmark icon on any material to save it here for quick access.'}
              </Text>
              {!isOffline && (
                <TouchableOpacity style={styles.emptyBtn} onPress={() => router.push('/(tabs)/search' as any)} activeOpacity={0.8}>
                  <Ionicons name="search" size={14} color="#fff" />
                  <Text style={styles.emptyBtnText}>Browse Materials</Text>
                </TouchableOpacity>
              )}
            </View>
          }
          renderItem={({ item }) => {
            const meta = TYPE_META[item.material.type] || { label: item.material.type, color: '#6B7280', icon: 'document' }
            return (
              <TouchableOpacity
                style={styles.card}
                onPress={() => router.push({ pathname: '/viewer', params: { file_url: item.material.file_url, title: item.material.title, color: meta.color } })}
                activeOpacity={0.8}
              >
                <View style={[styles.cardIcon, { backgroundColor: meta.color + '15' }]}>
                  <Ionicons name={meta.icon as any} size={22} color={meta.color} />
                </View>

                <View style={styles.cardInfo}>
                  <Text style={styles.cardTitle} numberOfLines={2}>{item.material.title}</Text>
                  <View style={styles.cardMeta}>
                    <View style={[styles.typePill, { backgroundColor: meta.color + '15' }]}>
                      <Text style={[styles.typeText, { color: meta.color }]}>{meta.label}</Text>
                    </View>
                    {item.material.courses?.name && (
                      <Text style={styles.courseName} numberOfLines={1}>{item.material.courses.name}</Text>
                    )}
                  </View>
                  <Text style={styles.savedAt}>Saved {timeAgo(item.created_at)}</Text>
                </View>

                <View style={styles.cardActions}>
                  {/* AI Chat */}
                  <TouchableOpacity
                    style={[styles.actionBtn, { backgroundColor: '#EFF6FF' }]}
                    onPress={() => router.push({ pathname: '/chat', params: { material_title: item.material.title, file_url: item.material.file_url, conversation_id: 'new' } })}
                    activeOpacity={0.75}
                  >
                    <Ionicons name="sparkles" size={15} color="#1A56DB" />
                  </TouchableOpacity>

                  {/* Quiz & Flashcards */}
                  <TouchableOpacity
                    style={[styles.actionBtn, styles.actionBtnQuiz]}
                    onPress={() => openQuiz(item)}
                    activeOpacity={0.75}
                  >
                    <Ionicons name={"school-outline" as any} size={15} color="#7C3AED" />
                  </TouchableOpacity>

                  {/* Remove bookmark */}
                  <TouchableOpacity
                    style={[styles.actionBtn, { backgroundColor: '#FEF2F2' }]}
                    onPress={() => handleRemove(item)}
                    activeOpacity={0.75}
                  >
                    {removing === item.id
                      ? <ActivityIndicator size="small" color="#EF4444" />
                      : <Ionicons name="trash-outline" size={15} color="#EF4444" />
                    }
                  </TouchableOpacity>
                </View>
              </TouchableOpacity>
            )
          }}
        />
      )}
    </View>
  )
}

