                      onChat={() => {}} onBookmark={() => toggleBookmark(m)} onQuiz={() => {}}
                    />
                  ))}
                </View>
              )}
              {studentList.length > 0 && (
                <View style={ss.matSection}>
                  <SectionHead title="Community Contributions" />
                  {studentList.map(m => (
                    <MaterialCard
                      key={m.id} item={m} isOfficial={false} isNew={false} isBookmarked={bookmarkedIds.has(m.id)} bookmarkLoading={bookmarkLoading === m.id}
                      onOpen={() => openMaterial(m)} onDownload={() => syncDownload(localMaterials.find(x => x.id === m.id))}
                      onChat={() => {}} onBookmark={() => toggleBookmark(m)} onQuiz={() => {}}
                    />
                  ))}
                </View>
              )}
            </>
          )}
        </View>
      </ScrollView>

      {sortOpen && (
        <View style={ss.dropdown}>
