// ─────────────────────────────────────────────
// Trending Card (horizontal)
// ─────────────────────────────────────────────
function TrendingCard({ tutorial }: { tutorial: Tutorial }) {
  const tc = typeConfig(tutorial.type)
  return (
    <ScalePress style={t.trendCard}>
      <ThumbnailPlaceholder subject={tutorial.subject} size="small" />
