import { supabase } from '@/lib/supabase';
import useAppStore from '@/store';
import * as SecureStore from 'expo-secure-store';
import { useCallback, useEffect, useState } from 'react';

interface SupabaseUser {
  id: string;
  email: string;
  user_metadata: any;
}
type AuthState = {
  user: any | null;
  loading: boolean;
  isAuthenticated: boolean;
};

export function useAuth() {
  const [state, setState] = useState<AuthState>({
    user: null,
    loading: true,
    isAuthenticated: false,
  });

  const setUser = useAppStore((s: any) => s.setUser);

  // Load token from secure storage
  useEffect(() => {
  const loadSession = async () => {
    const { data: { session }, error } = await supabase.auth.getSession();
    if (session) {
      setState({ user: session.user, loading: false, isAuthenticated: true });
      setUser(session.user);
    } else {
      setState({ user: null, loading: false, isAuthenticated: false });
    }
  };
    loadSession();
  }, []);

  // Login
  const login = useCallback(async (email: string, password: string) => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;

    if (data.session) {
      await SecureStore.setItemAsync('auth_token', data.session.access_token);
      setState({ user: data.user, loading: false, isAuthenticated: true });
      setUser(data.user);
    }
  }, []);

  // Logout
  const logout = useCallback(async () => {
    await supabase.auth.signOut();
    await SecureStore.deleteItemAsync('auth_token');
    setState({ user: null, loading: false, isAuthenticated: false });
    setUser(null);
  }, []);

  return {
    ...state,
    login,
    logout,
  };
}

import { useEffect, useState } from 'react';
import { Q } from '@nozbe/watermelondb';
import { useDatabase } from '../contexts/DatabaseContext';

// ─── Generic collection observer ────────────────────────────────────────────
// Subscribes to a WatermelonDB collection query and re-renders on change.
// This is the core pattern — all screen hooks build on this.

function useQuery(collection, conditions = []) {
  const db = useDatabase();
  const [records, setRecords] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const query = db.collections
      .get(collection)
      .query(...conditions);

    const subscription = query.observe().subscribe({
      next: (results) => {
        setRecords(results);
        setLoading(false);
      },
      error: (err) => {
        console.error(`[WatermelonDB] Error observing ${collection}:`, err);
        setLoading(false);
      },
    });

    return () => subscription.unsubscribe();
  }, [collection, JSON.stringify(conditions)]); // Added JSON.stringify for condition stability

  return { records, loading };
}

// ─── Users ───────────────────────────────────────────────────────────────────

export function useUser(id) {
  const db = useDatabase();
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!id) return;
    const subscription = db.collections
      .get('users')
      .findAndObserve(id)
      .subscribe({
        next: (record) => { setUser(record); setLoading(false); },
        error: () => setLoading(false),
      });
    return () => subscription.unsubscribe();
  }, [id]);

  return { user, loading };
}

